function DrawStackedGroupedColumnLine() {
  const { DualAxes } = components;
  const config = {
    data: [data, data],
    xField: "dimension_column",
    yField: ["measure_column", "secondary_measure_column"],
    geometryOptions: [
      {
        geometry: "column",
        isStack: true,
        isGroup: true,
        seriesField: "stack_column",
        groupField: "group_column"
      },
      { geometry: "line", seriesField: "line_series_column" }
    ]
  };
  return <div><DualAxes {...config} /></div>;
}
